import { useEffect, useState } from "react";
import api from "../api/api";

export default function AlertTable() {
  const [alerts, setAlerts] = useState([]);
  const [page, setPage] = useState(1);
  const [priority, setPriority] = useState("");
  const [loading, setLoading] = useState(true);
  const [hasNext, setHasNext] = useState(true); // użyj tylko jeśli API to zwraca

  useEffect(() => {
    setLoading(true);
    api.get("/alerts", {
      params: { page, priority }
    })
    .then((res) => {
      setAlerts(res.data.alerts);
      setHasNext(res.data.has_next ?? true); // obsługa backendu
    })
    .catch((err) => {
      console.error("Błąd ładowania alertów:", err);
      setAlerts([]);
    })
    .finally(() => {
      setLoading(false);
    });
  }, [page, priority]);

  return (
    <div className="p-6 bg-white rounded-xl shadow-md">
      <div className="mb-4 flex items-center gap-2">
        <label className="font-medium">Filtruj po priorytecie:</label>
        <input
          value={priority}
          onChange={(e) => {
            setPage(1); // reset strony
            setPriority(e.target.value);
          }}
          className="border px-2 py-1 rounded"
          placeholder="np. 1, 2, 3..."
        />
      </div>

      {loading ? (
        <p className="text-center text-gray-500">Ładowanie danych...</p>
      ) : (
        <table className="w-full border text-sm text-left">
          <thead className="bg-gray-100">
            <tr>
              <th className="border p-2">Czas</th>
              <th className="border p-2">Źródło</th>
              <th className="border p-2">Cel</th>
              <th className="border p-2">Priorytet</th>
              <th className="border p-2">Wiadomość</th>
            </tr>
          </thead>
          <tbody>
            {alerts.length === 0 ? (
              <tr>
                <td colSpan="5" className="text-center p-3 text-gray-500">
                  Brak danych do wyświetlenia
                </td>
              </tr>
            ) : (
              alerts.map((a, i) => (
                <tr key={i} className="hover:bg-gray-50">
                  <td className="border p-2">{a.timestamp}</td>
                  <td className="border p-2">{a.src_ip}</td>
                  <td className="border p-2">{a.dest_ip}</td>
                  <td className="border p-2">{a.priority}</td>
                  <td className="border p-2">{a.message}</td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      )}

      <div className="mt-4 flex justify-center gap-4">
        <button
          onClick={() => setPage(p => Math.max(1, p - 1))}
          disabled={page <= 1}
          className="px-3 py-1 bg-blue-500 text-white rounded disabled:opacity-50"
        >
          ← Poprzednia
        </button>
        <button
          onClick={() => setPage(p => p + 1)}
          disabled={!hasNext}
          className="px-3 py-1 bg-blue-500 text-white rounded disabled:opacity-50"
        >
          Następna →
        </button>
      </div>
    </div>
  );
}
